from flask import Flask, request, jsonify
import jwt
import os

app = Flask(__name__)

# Load secret keys from secure configuration (e.g., environment variables)
secret_key_internal = os.environ.get('SECRET_KEY_INTERNAL')
secret_key_public_api = os.environ.get('SECRET_KEY_PUBLIC_API')

def verify_jwt_token(token):
    try:
        # Allowlist algorithms for internal services and public APIs
        if token.split('.')[0] == 'HS256':
            payload = jwt.decode(
                token, secret_key_internal, 
                algorithms=["HS256"], options={"require": ["exp"]}
            )
        elif token.split('.')[0] == 'RS256':
            payload = jwt.decode(
                token, secret_key_public_api, 
                algorithms=["RS256"], options={"require": ["exp", "iss", "aud"]}
            )
        else:
            return None
    except jwt.ExpiredSignatureError:
        return None  # Token has expired
    except jwt.InvalidTokenError as e:
        print(f"Invalid token: {e}")
        return None

    return payload

@app.route('/verify-token', methods=['POST'])
def verify_token():
    token = request.json.get('token')
    if not token:
        return jsonify({'error': 'Missing token'}), 400
    
    payload = verify_jwt_token(token)
    if not payload:
        return jsonify({'error': 'Invalid or expired token'}), 401

    return jsonify(payload)

